import { useEffect, useState } from "react";
import { io } from "socket.io-client";

function Room({ room, userName, setPage }) {
  const [socket, setSocket] = useState(null);

  const [answer, setAnswer] = useState("");
  const [question, setQuestion] = useState(null);
  const [scores, setScores] = useState({});
  const [timeLeft, setTimeLeft] = useState(0);
  const [role, setRole] = useState(null);

  const [timerEnabled, setTimerEnabled] = useState(false);
  const [timeLimit, setTimeLimit] = useState(10);
  const sendAnswer = () => {
    socket?.emit("submit_answer", {
      answer,
    });
  };

  useEffect(() => {
    const newSocket = io("http://localhost:5000", {
      auth: {
        token: localStorage.getItem("token"),
      },
    });

    setSocket(newSocket);

    newSocket.on("role", (r) => {
      console.log("MY ROLE:", r);
      setRole(r);
    });

    newSocket.on("receive_question", (q) => {
      setQuestion(q);
      setTimeLeft(0);
    });

    newSocket.emit("join_room", {
      roomCode: room,
    });

    newSocket.on("timer_update", setTimeLeft);
    newSocket.on("update_scores", setScores);

    newSocket.on("quiz_finished", (s) => {
      alert("Квиз закончен!");
      console.log(s);
    });

    newSocket.on("force_next", () => {
      if (role === "organizer") {
        newSocket.emit("next_question", { roomCode: room });
      }
    });

    return () => newSocket.disconnect();
  }, [room]);

  return (
    <div>
      <button
        onClick={() => {
          if (window.confirm("Выйти из комнаты?")) {
            setPage("dashboard");
          }
        }}
      >
        🚪 Выйти
      </button>

      <h2>Комната: {room}</h2>

      {question && (
        <div>
          {question.imageUrl && <img src={question.imageUrl} width="200" />}
          <h3>{question.text}</h3>

          {question.options.map((opt, i) => (
            <button
              key={i}
              onClick={() => {
                socket?.emit("submit_answer", { answer: opt });
              }}
            >
              {opt}
            </button>
          ))}
        </div>
      )}

      {timeLeft > 0 && <h2>Время: {timeLeft}</h2>}

      {question?.type === "text" && (
        <>
          <input onChange={(e) => setAnswer(e.target.value)} />
          <button onClick={sendAnswer}>Ответить</button>
        </>
      )}

      <h3>Таблица лидеров:</h3>
      {Object.entries(scores)
        .sort((a, b) => b[1].score - a[1].score)
        .map(([u, s], index) => (
          <div key={u}>
            {index + 1}. {s.name || "Игрок"} — {s.score}
          </div>
      ))}

      {role === "organizer" && (
        <>
          <h3>Настройки</h3>

          <label>
            <input
              type="checkbox"
              onChange={(e) => setTimerEnabled(e.target.checked)}
            />
            Таймер
          </label>

          <input
            type="number"
            onChange={(e) => setTimeLimit(Number(e.target.value))}
          />

          <br />

          <button
            onClick={() =>
              socket?.emit("start_quiz", {
                roomCode: room,
                timerEnabled,
                timeLimit,
              })
            }
          >
            Старт квиза
          </button>

          <button
            onClick={() =>
              socket?.emit("next_question", { roomCode: room })
            }
          >
            Следующий вопрос
          </button>
        </>
      )}
    </div>
  );
}

export default Room;
